// products/products.service.ts
async findAllWithFilters(query: ProductQueryDto): Promise<{ items: Product[]; total: number; page: number; limit: number; totalPages: number }> {
  const { search, categoryId, minPrice, maxPrice, minStock, minRating, sortBy, sortOrder, page, limit } = query;

  const qb = this.productsRepository.createQueryBuilder('product')
    .leftJoinAndSelect('product.category', 'category')
    .leftJoinAndSelect('product.reviews', 'reviews');

  // Filtre par catégorie
  if (categoryId) {
    qb.andWhere('product.categoryId = :categoryId', { categoryId });
  }

  // Recherche textuelle (nom ou description)
  if (search) {
    qb.andWhere('(product.name ILIKE :search OR product.description ILIKE :search)', { 
      search: `%${search}%` 
    });
  }

  // Filtre par prix
  if (minPrice !== undefined) {
    qb.andWhere('product.price >= :minPrice', { minPrice });
  }
  if (maxPrice !== undefined) {
    qb.andWhere('product.price <= :maxPrice', { maxPrice });
  }

  // Filtre par stock
  if (minStock !== undefined) {
    qb.andWhere('product.stock >= :minStock', { minStock });
  }

  // Filtre par note moyenne (sous-requête)
  if (minRating !== undefined) {
    qb.andWhere(
      '(SELECT COALESCE(AVG(reviews.rating), 0) FROM reviews WHERE reviews.productId = product.id) >= :minRating',
      { minRating }
    );
  }

  // Tri - Attention: pour le tri par rating, il faut une sous-requête
  if (sortBy === 'rating') {
    qb.orderBy(`(SELECT COALESCE(AVG(r.rating), 0) FROM reviews r WHERE r.productId = product.id)`, sortOrder);
  } else {
    qb.orderBy(`product.${sortBy}`, sortOrder);
  }

  // Pagination
  const skip = (page - 1) * limit;
  qb.skip(skip).take(limit);

  const [items, total] = await qb.getManyAndCount();

  return {
    items,
    total,
    page,
    limit,
    totalPages: Math.ceil(total / limit),
  };
}
