// products/dto/cursor-pagination.dto.ts
export class CursorPaginationDto {
  @IsOptional()
  @IsString()
  cursor?: string; // Format: "createdAt_id" encodé en base64

  @IsOptional()
  @IsInt()
  @Min(1)
  @Max(50)
  @Type(() => Number)
  limit?: number = 10;
}

// products/products.service.ts
async findAllWithCursor(cursorDto: CursorPaginationDto) {
  const { cursor, limit } = cursorDto;
  const qb = this.productsRepository.createQueryBuilder('product')
    .leftJoinAndSelect('product.category', 'category')
    .orderBy('product.createdAt', 'DESC')
    .addOrderBy('product.id', 'DESC')
    .take(limit + 1); // Prendre un élément de plus pour savoir s'il y a une suite

  if (cursor) {
    const decoded = Buffer.from(cursor, 'base64').toString('ascii');
    const [createdAt, id] = decoded.split('_');
    qb.andWhere(
      '(product.createdAt < :createdAt OR (product.createdAt = :createdAt AND product.id < :id))',
      { createdAt: new Date(createdAt), id: parseInt(id) }
    );
  }

  const items = await qb.getMany();
  let nextCursor: string | null = null;

  if (items.length > limit) {
    const lastItem = items[limit - 1];
    const cursorValue = `${lastItem.createdAt.toISOString()}_${lastItem.id}`;
    nextCursor = Buffer.from(cursorValue).toString('base64');
    items.pop(); // Retirer l'élément supplémentaire
  }

  return { items, nextCursor };
}
